import React from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';

const PortfolioContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem;
`;

const PageTitle = styled(motion.h1)`
  font-size: 2.5rem;
  margin-bottom: 2rem;
  text-align: center;
  background: linear-gradient(45deg, #00b894, #00cec9);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
`;

const PortfolioGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  margin-top: 2rem;
`;

const PortfolioCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 1.5rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.3s ease;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
  }
`;

const PortfolioHeader = styled.div`
  display: flex;
  align-items: center;
  margin-bottom: 1rem;
`;

const PortfolioIcon = styled.div`
  font-size: 2rem;
  margin-right: 1rem;
`;

const PortfolioName = styled.h3`
  font-size: 1.3rem;
  color: #ffffff;
  margin: 0;
`;

const PortfolioValue = styled.div`
  font-size: 1.8rem;
  font-weight: bold;
  color: #00b894;
  margin-bottom: 0.5rem;
`;

const PortfolioChange = styled.div<{ positive: boolean }>`
  color: ${props => props.positive ? '#00b894' : '#ff6b6b'};
  font-size: 1.1rem;
  margin-bottom: 1rem;
`;

const PortfolioStats = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-top: 1rem;
`;

const StatItem = styled.div`
  text-align: center;
  padding: 0.5rem;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
`;

const StatLabel = styled.div`
  font-size: 0.8rem;
  color: #cccccc;
  margin-bottom: 0.2rem;
`;

const StatValue = styled.div`
  font-size: 1.1rem;
  font-weight: bold;
  color: #ffffff;
`;

const portfolioData = [
  {
    name: 'Stocks Portfolio',
    icon: '📊',
    value: '$45,230.50',
    change: '+3.2%',
    positive: true,
    stats: {
      holdings: '15',
      diversity: '78%'
    }
  },
  {
    name: 'Gold & Silver',
    icon: '💰',
    value: '$18,750.00',
    change: '+1.8%',
    positive: true,
    stats: {
      holdings: '2',
      diversity: '22%'
    }
  },
  {
    name: 'Crypto Assets',
    icon: '₿',
    value: '$12,450.75',
    change: '-2.1%',
    positive: false,
    stats: {
      holdings: '8',
      diversity: '15%'
    }
  },
  {
    name: 'Real Estate',
    icon: '🏠',
    value: '$85,000.00',
    change: '+0.5%',
    positive: true,
    stats: {
      holdings: '3',
      diversity: '50%'
    }
  }
];

const Portfolio: React.FC = () => {
  const { user } = useAuth();

  const totalValue = portfolioData.reduce((total, item) => {
    const value = parseFloat(item.value.replace(/[^0-9.]/g, ''));
    return total + value;
  }, 0);

  return (
    <PortfolioContainer>
      <PageTitle
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        💼 My Portfolio
      </PageTitle>

      <motion.div
        style={{ textAlign: 'center', marginBottom: '2rem' }}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.2 }}
      >
        <h2 style={{ color: '#00b894', fontSize: '2rem', marginBottom: '0.5rem' }}>
          Total Value: ${totalValue.toLocaleString()}
        </h2>
        <p style={{ color: '#cccccc' }}>Overall portfolio performance</p>
      </motion.div>

      <PortfolioGrid>
        {portfolioData.map((item, index) => (
          <PortfolioCard
            key={index}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.1 }}
            whileHover={{ scale: 1.02 }}
          >
            <PortfolioHeader>
              <PortfolioIcon>{item.icon}</PortfolioIcon>
              <PortfolioName>{item.name}</PortfolioName>
            </PortfolioHeader>

            <PortfolioValue>{item.value}</PortfolioValue>
            <PortfolioChange positive={item.positive}>
              {item.change} {item.positive ? '📈' : '📉'}
            </PortfolioChange>

            <PortfolioStats>
              <StatItem>
                <StatLabel>Holdings</StatLabel>
                <StatValue>{item.stats.holdings}</StatValue>
              </StatItem>
              <StatItem>
                <StatLabel>Diversity</StatLabel>
                <StatValue>{item.stats.diversity}</StatValue>
              </StatItem>
            </PortfolioStats>
          </PortfolioCard>
        ))}
      </PortfolioGrid>
    </PortfolioContainer>
  );
};

export default Portfolio;
